parameters.query:
INSERT INTO customer_preferences (chat_id, language, updated_at)
VALUES ({{ $('Start').first().json.chat_id }}, '{{ $('Start').first().json.lang_code || $('Start').first().json.auto_switch }}', NOW())
ON CONFLICT (chat_id) DO UPDATE SET language = '{{ $('Start').first().json.lang_code || $('Start').first().json.auto_switch }}', updated_at = NOW();

parameters.jsCode:
const startJson = $('Start').first().json;
const langCode = startJson.lang_code || startJson.auto_switch || 'en';
const autoSwitch = startJson.auto_switch || null;
const chatId = String(startJson.chat_id || '');

const autoSwitchMessages = {"hi": "मैं अब हिंदी में जवाब दूंगा। 👍\n\nआप क्या चाहेंगे?", "bn": "আমি এখন বাংলায় উত্তর দেব। 👍\n\nআপনি কী চান?", "te": "నేను ఇప్పుడు తెలుగులో జవాబు ఇస్తాను. 👍\n\nమీకు ఏమి కావాలి?", "ta": "நான் இப்போது தமிழில் பதில் சொல்கிறேன். 👍\n\nநீங்கள் என்ன விரும்புகிறீர்கள்?", "gu": "હું હવે ગુજરાતીમાં જવાબ આપીશ. 👍\n\nઆપ શું ઇચ્છો છો?", "kn": "ನಾನು ಈಗ ಕನ್ನಡದಲ್ಲಿ ಉತ್ತರಿಸುತ್ತೇನೆ. 👍\n\nನಿಮಗೆ ಏನು ಬೇಕು?", "ml": "ഞാൻ ഇനി മലയാളത്തിൽ മറുപടി നൽകും. 👍\n\nനിങ്ങൾക്ക് എന്ത് വേണം?", "or": "ମୁଁ ଏବେ ଓଡ଼ିଆରେ ଉତ୍ତର ଦେବି। 👍\n\nଆପଣ କ'ଣ ଚାହୁଁଛନ୍ତି?", "pa": "ਮੈਂ ਹੁਣ ਪੰਜਾਬੀ ਵਿੱਚ ਜਵਾਬ ਦੇਵਾਂਗਾ। 👍\n\nਤੁਸੀਂ ਕੀ ਚਾਹੁੰਦੇ ਹੋ?", "en": "I'll reply in English. 👍\n\nWhat would you like?"};

const confirmMessages = {
  en: "Got it! I'll reply in English from now on. 👍",
  hi: "ठीक है! मैं अब हिंदी में जवाब दूंगा। 👍",
  bn: "ঠিক আছে! এখন থেকে বাংলায় উত্তর দেব। 👍",
  te: "సరే! ఇప్పటి నుండి తెలుగులో సమాధానం ఇస్తాను. 👍",
  mr: "ठीक आहे! मी आता मराठीत उत्तर देईन. 👍",
  ta: "சரி! இனிமேல் தமிழில் பதில் சொல்கிறேன். 👍",
  gu: "ઠીક છે! હું હવે ગુજરાતીમાં જવાબ આપીશ. 👍",
  kn: "ಸರಿ! ಇನ್ನು ಮೇಲೆ ಕನ್ನಡದಲ್ಲಿ ಉತ್ತರಿಸುತ್ತೇನೆ. 👍",
  ml: "ശരി! ഇനി മലയാളത്തിൽ മറുപടി തരാം. 👍",
  or: "ঠিক আছে! ଏବେ ଓଡ଼ିଆରେ ଉତ୍ତର ଦେବି। 👍",
  pa: "ਠੀਕ ਹੈ! ਹੁਣ ਪੰਜਾਬੀ ਵਿੱਚ ਜਵਾਬ ਦੇਵਾਂਗਾ। 👍"
};

let bodyText;
if (autoSwitch) {
  // Auto-detected language: use shorter contextual message
  bodyText = autoSwitchMessages[autoSwitch] || autoSwitchMessages.en;
} else {
  bodyText = confirmMessages[langCode] || confirmMessages.en;
}

return [{ json: {
  chat_id: chatId,
  customer_ui_state: 'LANGUAGE_SET',
  message_type: 'button',
  body_text: bodyText,
  buttons: [
    { id: 'browse', title: 'Shop Items' },
    { id: 'view_cart', title: '🛒 Cart' },
  ],
} }];

const chatId = String($('Start').first().json.chat_id || '');
return [{ json: {
  chat_id: chatId,
  message_type: 'list',
  body_text: '🌐 Choose your language / अपनी भाषा चुनें',
  list_sections: JSON.stringify([
    {
      title: 'Popular Languages',
      rows: [
        { id: 'set_lang__en', title: 'English', description: 'English' },
        { id: 'set_lang__hi', title: 'हिंदी', description: 'Hindi' },
        { id: 'set_lang__bn', title: 'বাংলা', description: 'Bengali' },
        { id: 'set_lang__te', title: 'తెలుగు', description: 'Telugu' },
        { id: 'set_lang__mr', title: 'मराठी', description: 'Marathi' },
      ]
    },
    {
      title: 'More Languages',
      rows: [
        { id: 'set_lang__ta', title: 'Tamil', description: 'Tamil' },
        { id: 'set_lang__gu', title: 'Gujarati', description: 'Gujarati' },
        { id: 'set_lang__kn', title: 'Kannada', description: 'Kannada' },
        { id: 'set_lang__ml', title: 'Malayalam', description: 'Malayalam' },
        { id: 'set_lang__pa', title: 'Punjabi', description: 'Punjabi' },
      ]
    }
  ]),
} }];

const payload = $input.item.json;
return [{ json: {
  ...payload,
  bypass_path: true,
} }];

